import React, { useEffect, useState } from "react";

function App() {
    const [csvData, setCsvData] = useState("");

    useEffect(() => {
        fetch("/tedarik_performans.csv")
            .then((res) => res.text())
            .then((data) => {
                setCsvData(data);
            })
            .catch((err) => console.error(err));
    }, []);

    return (
        <div className="App">
            <h1>CSV Dosya İçeriği</h1>
            <pre>{csvData}</pre> {/* Ham CSV metni burada görünecek */}
        </div>
    );
}

export default App;
